{
  "model": "gpt-4o",
  "temperature": 0.2,
  "max_tokens": 8000,
  "auto_commit": true,
  "pre_commit_hooks": [
    "npm run lint",
    "npm run typecheck"
  ],
  "custom_prompts": {
    "refactor": "Refactor this code following SOLID principles",
    "optimize": "Optimize for performance and readability",
    "test": "Write comprehensive unit tests"
  },
  "tools": {
    "search": true,
    "shell": true,
    "file_tree": true
  },
  "memory": {
    "enabled": true,
    "max_messages": 50
  }
}
